var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"후우...... 아슬아슬했네.","JPN":"ふぅ……危なかったな。","ENG":"Phew... That was close.","TWN":"呼……有驚無險。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"수고했어, 플루토. 상으로 돌아가서 털손질 해 줄게.","JPN":"お疲れ様、プルートー。ご褒美に毛を手入れしてやるよ。","ENG":"Well done, Pluto. I'll brush your fur when we get back as a reward.","TWN":"辛苦了，布魯托。回去後我幫你修一下毛。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CAT_STREGA_NULL_NULL","text":{"KOREA":"야옹~","JPN":"にゃあ～","ENG":"Meow!","TWN":"喵喵~"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"CAT_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"후후후, 한순간이나마 이 몸을 긴장하게 만들다니 제법이었다. 제 3종 침식체.","JPN":"ふふふ、一瞬だったけどこの私を緊張させるなんてやるじゃない。第3種侵食体。","ENG":"Hah hah, I'm impressed, Category 3. You actually got me a little nervous back there.","TWN":"吼吼吼，能讓我這麼緊張，不愧是3類侵蝕體。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAURA_STREGA_EVENT_NULL","text":{"KOREA":"그 달달 떨리는 다리에 힘이나 주고 말하지 그래?","JPN":"そのブルブル震える脚を落ち着かせてから言ったらどうだ？","ENG":"A little nervous? Your legs are still shaking.","TWN":"妳倒是好好管管妳那抖個不停的腿吧。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_EVENT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INGRID_STREGA_NULL_NULL","text":{"KOREA":"이, 이건 떠는 게 아니라 긴장을 풀기 위한 스트레칭이라고!","JPN":"ふ、震えてるんじゃなくて、緊張を和らげるためのストレッチングよ！","ENG":"I'm not shaking! I'm just trying to work off the tension!","TWN":"這、這不是抖，這是為了緩解緊張的熱身運動！"},"stage":{"bg":"CORRIDOR_03","slots":{"L":null,"C":{"char_id":"INGRID_STREGA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"후훗. 그나저나 우리 유나, 굉장하던데?","JPN":"ふふっ。ところでユナ、すごいじゃない。","ENG":"Hah hah. Anyway, that was pretty impressive of you, Yuna.","TWN":"呼，尤娜，妳真是了不起啊？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"네? 제가요?","JPN":"え？　私ですか？","ENG":"Huh? Me?","TWN":"什麼？我嗎？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그래. <color=#ffd34c>인형</color>은 원래 쉽게 쓰러트릴 수 있는 상대가 아니거든.","JPN":"そうよ。<color=#ffd34c>人形</color>ってそう簡単に倒せる相手じゃないの。","ENG":"That's right. <color=#ffd34c>Puppets</color> are not that easy to take down.","TWN":"對啊。<color=#ffd34c>木偶</color>可不是輕而易舉就可以打敗的。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그런데 전투 중에 네가 날린 화염구를 맞은 뒤로는 꼭 실 끊어진 꼭두각시처럼 허우적대기만 하던걸?","JPN":"でも戦闘中にあなたの火の玉に当たってからは、糸が切れた操り人形みたいにバタバタしてたわ！","ENG":"But they waddled about like marionettes without their strings after one of your fireballs hit them.","TWN":"但在戰鬥的時候，木偶被你的火焰球擊中後就只能無力的掙扎了。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"제가 그랬어요......?","JPN":"私そんなことしましたっけ……？","ENG":"I did that?","TWN":"我嗎……？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"헤헤, 도망 다니느라 정신이 없어서 잘 모르겠어요.","JPN":"えヘヘ、逃げるのに夢中でよく覚えてないんです。","ENG":"Heh heh, to be honest, I had no idea because I was so busy running.","TWN":"嘿嘿，我就顧著逃跑了，還真沒注意到。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"그럼. 역시 메이 할머니의 손녀야. 자신감을 가져도 돼.","JPN":"うん。さすがメイお婆ちゃんの孫娘ね。自信を持っていいわ。","ENG":"You sure did. You really must take after Granny May. Have a little more confidence.","TWN":"嗯，果然是梅伊奶奶的孫女，要對自己有信心。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"덕분에 다친 사람 없이 큰 수확까지 얻었잖니.","JPN":"おかげで怪我人もなく、大きな収穫を得られたからね。","ENG":"Thanks to you, nobody got hurt and we got some extra goodies.","TWN":"多虧了妳，都沒有人受傷，收獲很不錯。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"수확이요?","JPN":"収穫？","ENG":"Goodies?","TWN":"收獲？"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"발푸르기스의 인형들은 아주 강력한 마법의 재료들로 만들어져 있거든.","JPN":"ヴァルプルギスの人形って、とても強力な魔法の材料でできてるの。","ENG":"Walpurgis puppets are made of extremely potent magic materials.","TWN":"魔女之夜城的木偶是用非常強大的魔法材料製成的。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"EVELYN_STREGA_NULL_NULL","text":{"KOREA":"할로윈 코스튬에 이것들을 섞어 만들면 효과가 훨씬 더 좋아질 거야.","JPN":"ハロウィンコスチュームにこれを混ぜて作れば、もっと効果が高くなるはずよ。","ENG":"If we mix these in with the Halloween costumes, they'll be even more effective.","TWN":"在萬聖節服裝裡添加這些材料效果會更好。"},"stage":{"bg":"CORRIDOR_03","slots":{"L":{"char_id":"EVELYN_STREGA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};